from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Return an adjective or demonym to be used before the subject
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return "American"
            # Simple heuristic: if object starts with "the ", drop it for adjective use
            if low_obj.startswith("the "):
                return obj[4:].strip()
            # For other nationalities, just return the object itself (could be e.g., "Canadian")
            return obj
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"with {obj} as backup pilot"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "leader":
            # Subject is an entity, object is a person
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        # Collect special role predicates and other information
        role_info = {"commander": None, "backuppilot": None, "crewmembers": []}
        other_triples = []
        nationality_sent = None

        for t in items:
            pred_low = t.predicate.lower()
            if pred_low == "nationality":
                demonym = phrase(subj, t.predicate, t.object)
                article = "an" if demonym[0].lower() in "aeiou" else "a"
                nationality_sent = f"{subj} is {article} {demonym}."
            elif pred_low == "commander":
                role_info["commander"] = t.object
            elif pred_low == "backuppilot":
                role_info["backuppilot"] = t.object
            elif pred_low == "crewmembers":
                role_info["crewmembers"].append(t.object)
            else:
                other_triples.append(t)

        # Build sentence for role information if any
        role_sentence = None
        if role_info["commander"] or role_info["backuppilot"] or role_info["crewmembers"]:
            parts = []
            if role_info["commander"]:
                parts.append(f"commander {role_info['commander']}")
            if role_info["backuppilot"]:
                parts.append(f"backup pilot {role_info['backuppilot']}")
            if role_info["crewmembers"]:
                crew = role_info["crewmembers"]
                if len(crew) == 1:
                    crew_list = crew[0]
                else:
                    crew_list = ", ".join(crew[:-1]) + f", and {crew[-1]}"
                parts.append(f"crew members {crew_list}")
            role_sentence = f"{subj} had " + ", ".join(parts) + "."

        # Build descriptor sentence for remaining predicates
        descriptors = [phrase(subj, t.predicate, t.object) for t in other_triples]
        descriptor_sentence = None
        if descriptors:
            if len(descriptors) == 1:
                descriptor_sentence = f"{subj} {descriptors[0]}."
            else:
                body = ", ".join(descriptors[:-1])
                descriptor_sentence = f"{subj} {body}, and {descriptors[-1]}."

        # Assemble final sentences in logical order
        if nationality_sent:
            sentences.append(nationality_sent)
        if role_sentence:
            sentences.append(role_sentence)
        if descriptor_sentence:
            sentences.append(descriptor_sentence)
        if not (nationality_sent or role_sentence or descriptor_sentence):
            sentences.append(f"{subj}.")

    # Combine sentences for different subjects
    return " ".join(sentences)

